// // This comment suggests that the circuit outputs high only when A and B are low or C and D are both high.
module top_module(
    input A,
    input B,
    input C,
    input D,
    output Y
);wire AB, CD, ABCD;
    and gate1(AB, A, B);
    and gate2(CD, C, D);
    not gate3(CD_not, CD);
    and gate4(ABCD, AB, CD_not);
    assign Y = ABCD;

endmodule
